const snmp = global.get('snmp');
if (!snmp) { msg.payload = { cpu: null }; return msg; }

const baseOid = '1.3.6.1.2.1.25.3.3.1.2';
const session = snmp.createSession(
    msg.host || '127.0.0.1',
    msg.community || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 0, timeout: 1500 }
);

session.on('error', function (err) {
    node.error('SNMP session error: ' + err.message);
});

const nodeRef = node;
const msgRef = msg;
const results = [];

session.subtree(baseOid, 50, function (varbinds) {
    varbinds.forEach(item => {
        if (item.type !== 129) {
            results.push(item.value);
        }
    });
}, function (error) {
    session.close();
    if (error) {
        nodeRef.error('SNMP subtree error: ' + error.message);
        msgRef.payload = { cpu: null };
    } else {
        let cores = results.length;
        let totalLoad = results.reduce((sum, val) => sum + Number(val), 0);
        let avgLoad = cores > 0 ? parseFloat((totalLoad / cores).toFixed(2)) : null;
        if (cores === 0) {
            msgRef.payload = { cpu: null };
        } else {
            msgRef.payload = { cpu: { cores: cores, load: avgLoad } };
        }
    }
    nodeRef.send(msgRef);
});
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { disk: null }; return msg; }

const session = snmp.createSession(
    msg.host || '127.0.0.1',
    msg.community || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 0, timeout: 1500 }
);

session.on('error', function (err) {
    node.error('SNMP session error: ' + err.message);
});

const nodeRef = node;
const msgRef = msg;
const baseOid = '1.3.6.1.2.1.25.2.3.1';
const storageTemp = {};

session.subtree(baseOid, 50, function (varbinds) {
    varbinds.forEach(item => {
        if (item.type !== 129) {
            let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
            let suffix = oidStr.replace(baseOid + '.', '');
            let parts = suffix.split('.');
            let prop = parts[0];
            let index = parts[1];

            if (!storageTemp[index]) {
                storageTemp[index] = { index: index };
            }
            let val = (Buffer.isBuffer(item.value)) ? item.value.toString('utf8') : item.value;
            if (prop === '2') storageTemp[index].type_oid = val;
            if (prop === '3') storageTemp[index].name = val;
            if (prop === '4') storageTemp[index].unit = parseInt(val);
            if (prop === '5') storageTemp[index].size = parseInt(val);
            if (prop === '6') storageTemp[index].used = parseInt(val);
        }
    });
}, function (error) {
    session.close();
    let result = { ramTotal: 0, ramUsed: 0, ramFree: 0, diskTotal: 0, diskUsed: 0, diskFree: 0, desc: {} };
    if (error) {
        nodeRef.error('SNMP subtree error: ' + error.message);
        msgRef.payload = { disk: null };
    } else {
        let hasData = false;
        Object.values(storageTemp).forEach(device => {
            if (!device.name || device.size == null) return;
            hasData = true;
            let nameUpper = String(device.name).toUpperCase();
            let isRam = nameUpper.includes('MEMORY') || nameUpper.includes('RAM') || nameUpper.includes('VIRTUAL');
            let totalBytes = (device.size * (device.unit || 1));
            let usedBytes = (device.used * (device.unit || 1));

            if (isRam) {
                result.ramTotal += totalBytes / (1024 * 1024);
                result.ramUsed += usedBytes / (1024 * 1024);
            } else {
                result.diskTotal += totalBytes / (1024 * 1024 * 1024);
                result.diskUsed += usedBytes / (1024 * 1024 * 1024);
                let gb = totalBytes / (1024 * 1024 * 1024);
                result.desc[device.name] = parseFloat(gb.toFixed(2));
            }
        });
        if (!hasData) {
            msgRef.payload = { disk: null };
        } else {
            result.ramTotal = parseFloat(result.ramTotal.toFixed(2));
            result.ramUsed = parseFloat(result.ramUsed.toFixed(2));
            result.ramFree = parseFloat((result.ramTotal - result.ramUsed).toFixed(2));
            result.diskTotal = parseFloat(result.diskTotal.toFixed(2));
            result.diskUsed = parseFloat(result.diskUsed.toFixed(2));
            result.diskFree = parseFloat((result.diskTotal - result.diskUsed).toFixed(2));
            msgRef.payload = { disk: result };
        }
    }
    nodeRef.send(msgRef);
});
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { interfaces: [] }; return msg; }

const session = snmp.createSession(
    msg.host || '127.0.0.1',
    msg.community || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 0, timeout: 1500 }
