const nodeRef = node;
const msgRef = msg;

const baseOid = '1.3.6.1.2.1.25.2.1';
const netTemp = {};

session.subtree(baseOid, 50, function (varbinds) {
    varbinds.forEach(item => {
        if (item.type !== 129) {
            let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
            let suffix = oidStr.replace(baseOid + '.', '');
            let parts = suffix.split('.');
            let prop = parts[0];
            let index = parts[1];

            if (!netTemp[index]) {
                netTemp[index] = { index: index };
            }
            let val = item.value;
            if (Buffer.isBuffer(val)) {
                if (prop === '6') {
                    let hex = val.toString('hex');
                    val = hex.match(/.{1,2}/g) ? hex.match(/.{1,2}/g).join(':').toUpperCase() : "Unknown";
                } else {
                    val = val.toString('utf8');
                }
            }
            if (prop === '2') netTemp[index].name = val;
            if (prop === '5') netTemp[index].speed = Number(val);
            if (prop === '6') netTemp[index].mac = val;
            if (prop === '8') netTemp[index].status = Number(val);
            if (prop === '10') netTemp[index].rx = Number(val);
            if (prop === '16') netTemp[index].tx = Number(val);
        }
    });
}, function (error) {
    session.close();

    if (error) {
        nodeRef.error('SNMP subtree error: ' + error.message);
        msgRef.payload = { interfaces: [] };
    } else {
        let interfaces = [];
        Object.values(netTemp).forEach(device => {
            if (!device.name) return;
            let nameUpper = String(device.name).toUpperCase();

            // ข้าม Loopback และ Virtual
            if (nameUpper.includes('LOOPBACK') || nameUpper.includes('VMWARE') || nameUpper.includes('VIRTUAL')) return;

            let statusStr = (device.status === 1) ? "ON" : "OFF";
            let speedMbps = device.speed ? (device.speed / 1000000) : 0;
            let rxMB = device.rx ? parseFloat((device.rx / (1024 * 1024)).toFixed(2)) : 0;
            let txMB = device.tx ? parseFloat((device.tx / (1024 * 1024)).toFixed(2)) : 0;

            interfaces.push({
                name: device.name,
                status: statusStr,
                received_MB: rxMB,
                sent_MB: txMB,
                speed_Mbps: speedMbps,
                mac_address: device.mac || "Unknown"
            });
        });

        msgRef.payload = { interfaces: interfaces };
    }

    nodeRef.send(msgRef);
});

return null;

