const pool = global.get('pgPool');
if (!pool) { node.error('pgPool not available in global context'); return null; }

const sql = 'SELECT machine_id, hostname, community, snmp_port FROM public.machines WHERE enabled = true';

pool.query(sql, [], function(err, result) {
    if (err) { node.warn('Device Registry: ' + err.message + ' — using fallback defaults'); return; }

    const registry = {};
    if (result && result.rows) {
        result.rows.forEach(row => {
            registry[row.machine_id] = {
                hostname: row.hostname || row.machine_id,
                community: row.community || 'public',
                snmp_port: row.snmp_port || 161
            };
        });
    }

    const g = global.get('deviceRegistry') || {};
    Object.assign(g, registry);
    global.set('deviceRegistry', g);
    node.log('Device registry loaded: ' + Object.keys(registry).length + ' devices');
});
return null;

const registry = global.get('deviceRegistry') || {};
const mid = msg.machine_id || msg.topic || '';
const device = registry[mid];
 //console.log(mid);
if (!device) {
    // Fallback to default for simulator
    msg.host = msg.host || 'ims-snmpsim';
    msg.community = msg.community || 'Netk@';
    msg.snmp_port = msg.snmp_port || 161;
} else {
    msg.host = device.hostname;
    msg.community = device.community;
    msg.snmp_port = device.snmp_port;
}
msg.machine_id = mid;
msg.topic = mid;
return msg;

const BATCH_INTERVAL_SEC = 30;
const BUFFER_MAX = 600;

try {
    if (!msg.payload || !Array.isArray(msg.payload)) return null;
    const deviceId = String(msg.topic || '').replace(/'/g, "''").trim();
    if (!deviceId) return null;

    // ── Phase 1 & 2: ประมวลผลข้อมูล ──────────────────────────────────────────
    const parsed = Object.assign({}, ...msg.payload);

    // ── Phase 3: เก็บลง Buffer ──────────────────────────────────────────────
    const now = Date.now();
    const bufKey = `batch_buf_${deviceId}`;
    const buffer = flow.get(bufKey) || { sys: [], net: [], ldi: [], lastFlush: now };
    const currentTime = new Date().toISOString();

    // System Metrics - Check if ALL are null, if so skip inserting sys_metrics
    if (parsed.cpu || parsed.disk || parsed.temp !== null) {
        buffer.sys.push({
            time: currentTime, 
            device_id: deviceId,
            cpu_cores: parsed.cpu ? parsed.cpu.cores : null,
            cpu_load_percent: parsed.cpu ? parsed.cpu.load : null,
            ram_total_mb: parsed.disk ? parsed.disk.ramTotal : null,
            ram_used_mb: parsed.disk ? parsed.disk.ramUsed : null,
            ram_free_mb: parsed.disk ? parsed.disk.ramFree : null,
            disk_total_gb: parsed.disk ? parsed.disk.diskTotal : null,
            disk_used_gb: parsed.disk ? parsed.disk.diskUsed : null,
            disk_free_gb: parsed.disk ? parsed.disk.diskFree : null,
            disk_description: parsed.disk ? JSON.stringify(parsed.disk.desc || {}) : '{}',
            temp_c: parsed.temp !== null ? parsed.temp : null
        });
    }

    // Network Metrics (Dynamic Interfaces)
    if (parsed.interfaces && Array.isArray(parsed.interfaces)) {
        parsed.interfaces.forEach(iface => {
            buffer.net.push({
                time: currentTime, 
                device_id: deviceId,
                iface_name: iface.name,
                rx_mbps: iface.received_MB || 0,
                tx_mbps: iface.sent_MB || 0,
                rx_errors: 0,
                tx_errors: 0,
                rx_drops: 0,
                tx_drops: 0, 
                status: iface.status === 'ON' ? 'UP' : 'DOWN'
            });
        });
    }

    // LDI Metrics
    if (parsed.ldi) {
        buffer.ldi.push({
            time: currentTime, 
            device_id: deviceId,
            throughput: parsed.ldi.throughput || 0,
            temperature: parsed.ldi.temperature || 0,
            humidity: parsed.ldi.humidity || 0,
            pressure: parsed.ldi.pressure || 0,
            joule_effect: parsed.ldi.joule_effect || 0,
            power_watt: parsed.ldi.power_watt || 0,
            vibration: parsed.ldi.vibration || 0,
            wifi_rssi: parsed.ldi.wifi_rssi || 0,
            wifi_snr: parsed.ldi.wifi_snr || 0
        });
    }

    // ── Phase 4: ตรวจสอบเงื่อนไขการส่งข้อมูล (Flush) ────────────────────────
    const elapsedSec = (now - buffer.lastFlush) / 1000;
    // Condition to flush if buffer has items
    const totalItems = buffer.sys.length + buffer.net.length + buffer.ldi.length;

    if (elapsedSec < BATCH_INTERVAL_SEC && buffer.sys.length < BUFFER_MAX) {
        flow.set(bufKey, buffer);
        return null;
    }

    // ── Phase 5: สั่งรัน SQL แบบคู่ขนาน (Concurrent INSERT) ─────────────────
    const pool = global.get('pgPool');
    if (!pool) {
        node.error('pgPool is missing in global context!');
        return null;
    }

    const queries = [
        buildQuery('public.sys_metrics', ['"time"', 'device_id', 'cpu_cores', 'cpu_load_percent', 'ram_total_mb', 'ram_used_mb', 'ram_free_mb', 'disk_total_gb', 'disk_used_gb', 'disk_free_gb', 'disk_description', 'temp_c'], buffer.sys),
        buildQuery('public.net_metrics', ['"time"', 'device_id', 'iface_name', 'rx_mbps', 'tx_mbps', 'rx_errors', 'tx_errors', 'rx_drops', 'tx_drops', 'status'], buffer.net),
        buildQuery('public.ldi_metrics', ['"time"', 'device_id', 'throughput', 'temperature', 'humidity', 'pressure', 'joule_effect', 'power_watt', 'vibration', 'wifi_rssi', 'wifi_snr'], buffer.ldi)
    ].filter(q => q !== null);

    if (queries.length === 0) {
        flow.set(bufKey, { sys: [], net: [], ldi: [], lastFlush: Date.now() });
        return null;
    }

    Promise.all(queries.map(q => pool.query(q.sql, q.params)))
        .then(() => {
            node.log(`Batch INSERT OK: Sys=${buffer.sys.length}, Net=${buffer.net.length}, LDI=${buffer.ldi.length}`);
            flow.set(bufKey, { sys: [], net: [], ldi: [], lastFlush: Date.now() });
        })
        .catch(err => {
            node.error(`Batch INSERT Failed: ${err.message}`);
            buffer.lastFlush = Date.now();
            flow.set(bufKey, buffer);
        });

    return null;

} catch (err) {
    node.error(`Parser Crash: ${err.message}`, msg);
    return null;
}

function buildQuery(tableName, columns, rows) {
    if (!rows || rows.length === 0) return null;
    const params = [];
    const placeholders = rows.map((row, rowIndex) => {
        const tokens = columns.map((col, colIndex) => {
            const key = col.replace(/"/g, '');
            let val = row[key];
            if (val === null) {
                return 'NULL';
            }
            params.push(val);
            // param index must match the actual number of pushed params
            const paramIndex = params.length;
            return key === 'disk_description' ? `$${paramIndex}::jsonb` : `$${paramIndex}`;
        });
        return `(${tokens.join(',')})`;
    }).join(',');

    return {
        sql: `INSERT INTO ${tableName} (${columns.join(',')}) VALUES ${placeholders}`,
        params
    };
}

const registry = global.get('deviceRegistry') || {};
//console.log(registry);

const devices = Object.keys(registry).map(id => {
    return {
        machine_id: id,
        host: registry[id].hostname,
        community: registry[id].community,
        snmp_port: registry[id].snmp_port
    };
});

if (devices.length === 0) {
    // Fallback if registry empty
    devices.push({ machine_id: 'ERP-MASTER-UBUNTU' }, { machine_id: 'ERP-MASTER-WINDOWS' });
}

return [devices];

const input = msg.subnet || '192.168.1.';
const msgs = [];

// ถ้าระบุเป็นวงแลน (ลงท้ายด้วยจุด) ให้สร้าง 254 IPs
if (input.endsWith('.')) {
