const snmp = global.get('snmp');
if (!snmp) return null;

const community = (msg.ip === 'ims-snmpsim') ? 'Netk@' : 'public';

const session = snmp.createSession(msg.ip, community, { 
    port: 161, 
    version: snmp.Version2c, 
    retries: 1, 
    timeout: 2000 
});

const nodeRef = node;
const msgRef = msg;
msgRef.community = community;

session.get(['1.3.6.1.2.1.1.5.0'], function (error, varbinds) {
    if (error) {
        nodeRef.warn("Discovery failed for " + msgRef.ip + ": " + error.message);
    } else {
        // ถ้ายิงแล้วตอบกลับมา (ถึงจะไม่เจอ sysName ก็ตาม) แปลว่าเครื่องนี้มีตัวตนอยู่จริง!
        if (varbinds.length > 0 && !snmp.isVarbindError(varbinds[0])) {
            let val = varbinds[0].value;
            msgRef.sysName = Buffer.isBuffer(val) ? val.toString('utf8') : String(val);
        } else {
            // Simulator ไม่มีค่า sysName ให้ตอบกลับมา เลยเข้าเคสนี้แทน
            msgRef.sysName = "AUTO-" + msgRef.ip; 
        }
        nodeRef.send(msgRef);
    }
    session.close();
});

return null;

const pool = global.get('pgPool');
if (!pool) return null;

const machineId = (msg.sysName && msg.sysName.trim() !== '') ? msg.sysName.trim() : 'AUTO-' + msg.ip;
const hostname = msg.ip;
const community = msg.community || 'public';

const sql = `
    INSERT INTO public.machines (machine_id, hostname, community, snmp_port, enabled)
    VALUES ($1, $2, $3, 161, true)
    ON CONFLICT (machine_id) DO UPDATE
    SET hostname = EXCLUDED.hostname,
        community = EXCLUDED.community
`;

pool.query(sql, [machineId, hostname, community])
    .then(result => {
        node.warn(`✅ Upserted device: ${machineId} (${hostname})`);
    })
    .catch(err => {
        node.error(`Failed to register ${hostname}: ${err.message}`);
    });

return null;
